INSERT INTO `reviews` (`name`, `content`, `rating`, `display_order`) VALUES
('Jane Whitfield', 'Speedy Iron/Laundry is the most wonderful Company. Have used them for twenty years and not once have they let me down. Ironing of all kinds perfectly done, dry cleaning too. Latterly I have been using the laundry service for my bedding & am as impressed as I expected to be!', 5, 0),
('Anna Fountain', 'Amazing! My long delicate dress was very dirty after dragging on the floor at a wedding, I was so surprised they managed to get the dirt out of the bottom of the dress. Highly recommend !!', 5, 1),
('Ann', 'We have used Speedy Iron for about 15 years or possibly more. One day I had a lot of ironing to do for a holiday and needed it quickly. It was a 24hour approx turn around service. They came to pick up my bag of ironing and weighed it.', 5, 2),
('Jonathan Martin', 'Excellent service!! For both cleanliness and liaison''s!! Thank you for going beyond expectations!!', 5, 3),
('Les Poole', 'Best customer service I''ve experienced in a long time, both from the office staff & the pick up/delivery service. Nothing too much trouble & any queries responded to & resolved immediately. Provides a first class service.', 5, 4),
('Andrew Daw', 'We have used Speedy Laundry for several years and they have always been reliable, as well as speedy no matter how much we ask them to do. We would recommend them to anyone who needs an ironing or dry cleaning service.', 5, 5),
('Nick Winfield', 'Excellent service, we have been using Speedy Laundry for years for our ironing and they have NEVER let us down. Trustworthy and reliable, I would not hesitate to recommend them.', 5, 6),
('Malcolm Cleaver', 'Fantastic collect and drop off ironing service. Been using them for over 20 years and they''ve never missed a beat. Top quality personal service.', 5, 7);
